// FAQ knowledge base (local, sem LLM). PII scrubber.
const item = $input.item.json;
const raw = ((item.body && item.body.message && item.body.message.text) || '').toLowerCase().trim();

// PII patterns
const patterns = {
  cpf: /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g,
  rg: /\b\d{1,2}\.?\d{3}\.?\d{3}-?\d{1}\b/g,
  phone: /\b\(\d{2}\)\s?9?\d{4}-?\d{4}\b/g,
  email: /\b[\w.-]+@[\w.-]+\.\w+\b/g
};
let scrubbed = raw;
let redactionCount = 0;
for (const [type, pattern] of Object.entries(patterns)) {
  const matches = scrubbed.match(pattern);
  if (matches) {
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
  }
}

// FAQ knowledge base (intencao -> resposta)
const kb = {
  'horario': 'Atendemos de segunda a sexta, 09h-17h. Em urgente, procure o plantao no 1o andar.',
  'endereco|local|onde': 'Cartorio 2 Notas Uberlandia - Av. Paulo Gracindo, 150 - Centro. Estacionamento no local.',
  'documento|rg|cpf': 'Para tirar 2a via de RG, procurar SEJUSP. Para CPF, procurar Receita Federal. No cartorio fazemos autenticacao e reconhecimento de firma.',
  'cust|emolumento|valor|tabela': 'Valores conforme tabela MG 2026. Posso consultar agora - me diga o tipo de servico (certidao, escritura, procuracao, etc).',
  'agendar|agendamento|horario': 'Quer agendar atendimento? Me diga dia da semana e horario de preferencia.',
  'pix|pagament|cartao': 'Aceitamos PIX, cartao (credito/debito) e dinheiro. Pagamento apos conclusao do servico.',
  'certidao': 'Emitamos certidoes: casamento, negativa, positiva, nascimento, obito. Me diga qual precisa.',
  'escritura': 'Fazemos escrituras de compra/venda, doacao, permuta, procurações. Agende com um escrevente.',
  'procuracao': 'Procuracao precisa de comparecimento pessoal do outorgante + 2 testemunhas com RG/CPF.',
  'protesto': 'Protesto de titulos: 2a a 6a, das 09h-16h. Pagamento ou cancelamento tira o protesto em 5 dias uteis.'
};

let resposta = null;
let intencao = null;
for (const [pattern, resp] of Object.entries(kb)) {
  if (new RegExp(pattern, 'i').test(scrubbed)) {
    resposta = resp;
    intencao = pattern.split('|')[0];
    break;
  }
}

if (!resposta) {
  resposta = 'Nao encontrei resposta automatica. Vou transferir para um atendente humano. Aguarde.';
  intencao = 'unknown';
}

return { json: { sender: (item.body && item.body.sender) || 'unknown', scrubbed, redactionCount, intencao, resposta } };
